    def __init__(self) -> None:
        self._streams: Dict[str, List[Event]] = defaultdict(list)
        self._all_events: List[Event] = []
        self._snapshots: Dict[str, Snapshot] = {}

    def load_stream(self, aggregate_id: str, after_version: int = 0) -> List[Event]:
        return [e for e in self._streams[aggregate_id] if e.version > after_version]

    def append(
        self,
        aggregate_id: str,
        expected_version: int,
        new_events: List[Event],
    ) -> None:
        stream = self._streams[aggregate_id]
        current_version = stream[-1].version if stream else 0
        if current_version != expected_version:
            raise ConcurrencyError(
                f"Expected version {expected_version}, got {current_version}"
            )

        next_version = current_version
        for e in new_events:
            next_version += 1
            stored = self._with_version(e, next_version)
            stream.append(stored)
            self._all_events.append(stored)

    def all_events_since(self, offset: int) -> List[Event]:
        return self._all_events[offset:]

    def event_count(self) -> int:
        return len(self._all_events)

    def save_snapshot(self, snapshot: Snapshot) -> None:
        existing = self._snapshots.get(snapshot.aggregate_id)
        if existing is None or snapshot.version >= existing.version:
            self._snapshots[snapshot.aggregate_id] = snapshot

    def load_snapshot(self, aggregate_id: str) -> Optional[Snapshot]:
        return self._snapshots.get(aggregate_id)

