        self.event_id = str(uuid.uuid4())
        self.aggregate_id = aggregate_id
        self.timestamp = datetime.now()

    @abstractmethod
    def apply(self, aggregate: 'Aggregate') -> None:
        pass


class Aggregate(ABC):
    def __init__(self, aggregate_id: str):
        self.id = aggregate_id
        self.version = 0
        self._changes: List[Event] = []

    @classmethod
    def replay_events(cls, aggregate_id: str, events: List[Event]) -> 'Aggregate':
        aggregate = cls(aggregate_id)
        for event in events:
            event.apply(aggregate)
            aggregate.version += 1
        return aggregate

    def apply_change(self, event: Event) -> None:
        event.apply(self)
        self._changes.append(event)

    def get_uncommitted_changes(self) -> List[Event]:
        return self._changes

    def clear_uncommitted_changes(self) -> None:
        self._changes = []


class EventStore:
    def __init__(self):
        self._store: Dict[str, List[Event]] = {}
        self._snapshots: Dict[str, Tuple[Aggregate, int]] = {}
        self._projections: Dict[str, Callable[[Event], None]] = {}

    def save(self, aggregate: Aggregate) -> None:
        changes = aggregate.get_uncommitted_changes()
        if aggregate.id not in self._store:
            self._store[aggregate.id] = []
        self._store[aggregate.id].extend(changes)
        aggregate.clear_uncommitted_changes()

    def get_events(self, aggregate_id: str) -> List[Event]:
        return self._store.get(aggregate_id, [])

    def get_aggregate(self, aggregate_class: Type[A], aggregate_id: str) -> A:
        # Check for snapshot first
        if aggregate_id in self._snapshots:
            snapshot, version = self._snapshots[aggregate_id]
            events = self.get_events(aggregate_id)[version:]
            if events:
                snapshot = aggregate_class.replay_events(aggregate_id, events)
                snapshot.version += version
            return snapshot

        events = self.get_events(aggregate_id)
        if not events:
            raise ValueError(f"Aggregate {aggregate_id} not found")
        return aggregate_class.replay_events(aggregate_id, events)

    def save_snapshot(self, aggregate: Aggregate) -> None:
        self._snapshots[aggregate.id] = (aggregate, aggregate.version)

    def register_projection(self, name: str, projection: Callable[[Event], None]) -> None:
        self._projections[name] = projection

    def process_new_events(self) -> None:
        # In a real system, this would only process new events since last check
        for events in self._store.values():
            for event in events:
                for projection in self._projections.values():
                    projection(event)


