    def __init__(self, event_store: EventStore):
        self.event_store = event_store
        self.snapshot_threshold = 5  # Create snapshot every 5 events

    def save(self, account: BankAccount):
        changes = account.get_uncommitted_changes()
        if not changes:
            return

        # 1. Save Events
        self.event_store.save_events(
            account.aggregate_id, 
            changes, 
            account.version - len(changes)
        )

        # 2. Snapshotting Logic (Performance Optimization)
        # If the number of events since last snapshot exceeds threshold, save snapshot
        # In a real system, you'd track the version of the last snapshot, 
        # but here we can infer from total events count.
        total_events = len(self.event_store.get_events(account.aggregate_id))
        if total_events >= self.snapshot_threshold and total_events % self.snapshot_threshold == 0:
            snapshot_event = AccountSnapshotted(
                account.aggregate_id,
                account.version,
                state={
                    'owner': account.owner,
                    'balance': account.balance,
                    'is_closed': account.is_closed
                }
            )
            # We treat the snapshot as an event in the stream for simplicity
            # In production, snapshots are usually stored separately
            self.event_store.save_events(account.aggregate_id, [snapshot_event], account.version)
            self.event_store.save_snapshot(account.aggregate_id, {
                'owner': account.owner,
                'balance': account.balance,
                'is_closed': account.is_closed,
                'version': account.version
            })
            print(f"   > Snapshot saved for {account.aggregate_id} (v{account.version})")

        account.mark_changes_as_committed()

