        account = BankAccount(aggregate_id)

        # 1. Try load from snapshot
        snapshot = self.event_store.get_snapshot(aggregate_id)
        if snapshot:
            # Replay events after snapshot
            all_events = self.event_store.get_events(aggregate_id)
            # Filter events with version > snapshot version
            events_to_replay = [e for e in all_events if e.version > snapshot['version']]

            # Manually apply snapshot state (bypassing standard apply for speed)
            account.owner = snapshot['owner']
            account.balance = snapshot['balance']
            account.is_closed = snapshot['is_closed']
            account.version = snapshot['version']

            # Replay remaining events
            for event in events_to_replay:
                account.apply(event, is_new=False)
        else:
            # Load from beginning
            events = self.event_store.get_events(aggregate_id)
            account.load_from_history(events)

